class RestrictedUnpickler(pickle.Unpickler):
    """
    A restricted unpickler that only allows loading specific safe classes.
    This prevents arbitrary code execution via malicious pickle files.
    """

    ALLOWED_MODULES = ALLOWED_MODEL_CLASSES

    def find_class(self, module: str, name: str) -> Any:
        # Check if the module is in our allowlist
        if module in self.ALLOWED_MODULES:
            return super().find_class(module, name)

        # Allow basic builtins that sklearn needs
        if module == "builtins" and name in ("set", "frozenset", "dict", "list", "tuple", "bytes", "bytearray"):
            return super().find_class(module, name)

        # Allow copy_reg for reconstruction
        if module == "copyreg" and name == "_reconstructor":
            return super().find_class(module, name)

        # Allow collections.OrderedDict
        if module == "collections" and name == "OrderedDict":
            return super().find_class(module, name)

        raise pickle.UnpicklingError(
            f"Forbidden class: {module}.{name}. "
            f"Only approved sklearn model classes are allowed."
        )


def safe_pickle_load(data: bytes) -> Any:
    """
    Safely load a pickle file using the restricted unpickler.
    This prevents deserialization of arbitrary objects that could
    execute malicious code.
    """
    return RestrictedUnpickler(io.BytesIO(data)).load()


def validate_pickle_header(data: bytes) -> bool:
    """Validate that the data looks like a valid pickle stream."""
    if len(data) < 2:
        return False
    # Check for valid pickle protocol opcodes
    first_byte = data[0]
    # Protocol 0-5 start bytes
    valid_starts = {
        0x80,  # PROTO opcode (protocol 2+)
        0x28,  # MARK
        0x7d,  # EMPTY_DICT
        0x5d,  # EMPTY_LIST
        0x29,  # EMPTY_TUPLE
        0x4e,  # NONE
        0x89,  # NEWOBJ_EX
    }
    # Also allow text-mode pickle (protocol 0)
    if first_byte in valid_starts or (0x30 <= first_byte <= 0x39) or first_byte == ord('('):
        return True
    return False


class InferenceRequest(BaseModel):
    model_id: str
    input_data: list


class ModelInfo(BaseModel):
    model_id: str
