def get_tenant_id(credentials: HTTPAuthorizationCredentials = Depends(security)) -> str:
    """Authenticate and return tenant ID based on API key."""
    token = credentials.credentials
    for tenant_id, api_key in tenant_api_keys.items():
        if hmac.compare_digest(token, api_key):
            logger.info(f"Authenticated tenant: {tenant_id}")
            return tenant_id
    raise HTTPException(status_code=401, detail="Invalid API key")


def compute_file_hash(data: bytes) -> str:
    """Compute SHA-256 hash of file data for integrity verification."""
    return hashlib.sha256(data).hexdigest()


