@app.post("/models/upload", response_model=ModelInfo)
async def upload_model(
    model_name: str = Form(...),
    model_file: UploadFile = File(...),
    tenant_id: str = Depends(get_tenant_id),
):
    """
    Upload a serialized sklearn model file.
    The model is validated using a restricted unpickler that only allows
    approved sklearn classes, preventing arbitrary code execution.
    """
    logger.info(f"Tenant {tenant_id} uploading model: {model_name}")

    # Validate file extension
    if not model_file.filename.endswith(('.pkl', '.pickle', '.joblib')):
        raise HTTPException(
            status_code=400,
            detail="Only .pkl, .pickle, and .joblib files are accepted"
        )

    # Read file content with size limit
    content = await model_file.read()

    if len(content) > MAX_MODEL_SIZE_BYTES:
        raise HTTPException(
            status_code=413,
            detail=f"Model file exceeds maximum size of {MAX_MODEL_SIZE_BYTES // (1024*1024)}MB"
        )

    if len(content) == 0:
        raise HTTPException(status_code=400, detail="Empty file uploaded")

    # Validate pickle header
    if not validate_pickle_header(content):
        raise HTTPException(
            status_code=400,
            detail="File does not appear to be a valid pickle file"
        )

    # Compute file hash for integrity
    file_hash = compute_file_hash(content)

    # Check for duplicate uploads by this tenant
    for mid, minfo in models_store.items():
        if minfo["tenant_id"] == tenant_id and minfo["file_hash"] == file_hash:
            logger.warning(f"Duplicate model upload detected for tenant {tenant_id}")
            raise HTTPException(
                status_code=409,
                detail=f"This model has already been uploaded as model_id: {mid}"
            )

    # SECURITY: Use restricted unpickler to safely deserialize
    # This prevents arbitrary code execution from malicious pickle files
    try:
        model = safe_pickle_load(content)
    except pickle.UnpicklingError as e:
        logger.error(f"Restricted unpickler blocked model from tenant {tenant_id}: {e}")
        raise HTTPException(
            status_code=400,
            detail=f"Model contains disallowed classes: {str(e)}. "
                   f"Only approved sklearn model types are permitted."
        )
    except Exception as e:
        logger.error(f"Failed to deserialize model from tenant {tenant_id}: {e}")
        raise HTTPException(
            status_code=400,
            detail=f"Failed to deserialize model: {str(e)}"
        )

    # Validate that the loaded object has a predict method (is a valid model)
    if not hasattr(model, 'predict'):
        raise HTTPException(
            status_code=400,
            detail="Uploaded object does not have a 'predict' method. "
                   "Please upload a valid sklearn model."
        )

    # Generate unique model ID
    model_id = f"{tenant_id}_{uuid.uuid4().hex[:12]}"

    # Store model file on disk in tenant-isolated directory
    tenant_dir = os.path.join(UPLOAD_DIR, tenant_id)
    os.makedirs(tenant_dir, exist_ok=True)
    model_path = os.path.join(tenant_dir, f"{model_id}.pkl")

    with open(model_path, "wb") as f:
        f.write(content)

    # Store model metadata and loaded model in memory
    model_info = {
        "model_id": model_id,
        "model_name": model_name,
        "tenant_id": tenant_id,
        "uploaded_at": datetime.utcnow().isoformat(),
        "file_size_bytes": len(content),
        "file_hash": file_hash,
        "file_path": model_path,
        "model_object": model,
        "status": "ready",
    }
    models_store[model_id] = model_info

    logger.info(f"Model {model_id} uploaded successfully for tenant {tenant_id}")

    return ModelInfo(
        model_id=model_id,
        model_name=model_name,
        tenant_id=tenant_id,
        uploaded_at=model_info["uploaded_at"],
        file_size_bytes=len(content),
        file_hash=file_hash,
        status="ready",
    )


@app.post("/models/predict", response_model=InferenceResponse)
async def predict(
    request: InferenceRequest,
    tenant_id: str = Depends(get_tenant_id),
):
    """
    Run inference using an uploaded model.
    Tenant isolation is enforced - tenants can only use their own models.
    """
    model_id = request.model_id

    # Check if model exists
    if model_id not in models_store:
        raise HTTPException(status_code=404, detail=f"Model {model_id} not found")

    model_info = models_store[model_id]

    # SECURITY: Enforce tenant isolation
    if model_info["tenant_id"] != tenant_id:
        logger.warning(
            f"Tenant {tenant_id} attempted to access model {model_id} "
            f"owned by {model_info['tenant_id']}"
        )
        raise HTTPException(
            status_code=403,
            detail="Access denied. You can only use your own models."
        )

    if model_info["status"] != "ready":
        raise HTTPException(
            status_code=503,
            detail=f"Model {model_id} is not ready. Status: {model_info['status']}"
        )

    model = model_info["model_object"]

    try:
        input_array = np.array(request.input_data)

        # Ensure 2D input
        if input_array.ndim == 1:
            input_array = input_array.reshape(1, -1)

        start_time = datetime.utcnow()
        predictions = model.predict(input_array)
        end_time = datetime.utcnow()

        inference_time_ms = (end_time - start_time).total_seconds() * 1000

        logger.info(
            f"Inference completed for model {model_id}, tenant {tenant_id}, "
            f"time: {inference_time_ms:.2f}ms"
        )

        return InferenceResponse(
            model_id=model_id,
            predictions=predictions.tolist(),
            inference_time_ms=round(inference_time_ms, 2),
        )

    except ValueError as e:
        raise HTTPException(
            status_code=400,
            detail=f"Invalid input data format: {str(e)}"
        )
    except Exception as e:
        logger.error(f"Inference error for model {model_id}: {e}")
        raise HTTPException(
            status_code=500,
            detail=f"Inference failed: {str(e)}"
        )


